import{_ as a,o as r,c as o,a2 as d}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"G11: 前十大客戶與供應商穩定度 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/4967_十銓/20260429/G11_前十大客戶與供應商穩定度.md","filePath":"審計報告庫/經營審計/4967_十銓/20260429/G11_前十大客戶與供應商穩定度.md"}'),e={name:"審計報告庫/經營審計/4967_十銓/20260429/G11_前十大客戶與供應商穩定度.md"};function n(s,t,l,i,h,g){return r(),o("div",null,[...t[0]||(t[0]=[d('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="g11-前十大客戶與供應商穩定度-投資研究員-審計報告" tabindex="-1">G11: 前十大客戶與供應商穩定度 - 投資研究員 審計報告 <a class="header-anchor" href="#g11-前十大客戶與供應商穩定度-投資研究員-審計報告" aria-label="Permalink to &quot;G11: 前十大客戶與供應商穩定度 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>近三年中，前十大客戶與供應商變動情形為何？客戶集中度風險是否正在惡化？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>Top 1 客戶佔比從 54.67% 驟降至 25.15%，集中度大幅改善。惟前兩大仍貢獻 40.56% 營收，韓系供應鏈約 70%。掉單風險：由嚴峻降至可控，尚未達安全水位。</p><p><strong>數據時效</strong>：根據截至 2025 年（114年度）最新年報數據。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指標</th><th>2023年</th><th>2024年</th><th>2025年</th><th>趨勢</th></tr></thead><tbody><tr><td>Top 1 客戶佔比</td><td><strong>54.67%</strong> ▲</td><td><strong>43.97%</strong> ▲</td><td><strong>25.15%</strong> ▼</td><td>大幅下降</td></tr><tr><td>Top 2 客戶佔比</td><td>僅1家逾10%</td><td>僅1家逾10%</td><td><strong>40.56%</strong></td><td>新增乙公司</td></tr><tr><td>毛利率</td><td><strong>8%</strong> ▼</td><td><strong>11%</strong> ▲</td><td><strong>14%</strong> ▲</td><td>連年改善</td></tr><tr><td>營業利益率</td><td><strong>1.9%</strong> ▼</td><td><strong>2.7%</strong> ▼</td><td><strong>6.9%</strong> ▲</td><td>顯著回升</td></tr><tr><td>營業費用率</td><td><strong>6.0%</strong></td><td><strong>8.5%</strong> ▲</td><td><strong>7.4%</strong></td><td>費用管控得宜</td></tr><tr><td>韓系供應鏈</td><td>~70%（推估）</td><td>~70%（推估）</td><td>~70%（推估）</td><td>集中度居高</td></tr></tbody></table><p><strong>診斷見解</strong>：三年內 Top 1 從 54.67% 砍半至 25.15%，是極具說服力的客戶分散成果。2025 年新增乙公司（15.41%），證實 B2B 工控策略已落地。惟年報僅揭露逾 10% 之大客戶，前十大累計佔比無法確認。供應鏈端韓系原廠約 70% 構成結構性脆弱點，記憶體通路商本質被雙向擠壓。診斷評級：<strong>A-（良偏弱）</strong>——客戶分散突破性進展，但供應鏈與區域集中度仍是弱點。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、客戶集中度變動" tabindex="-1">一、客戶集中度變動 <a class="header-anchor" href="#一、客戶集中度變動" aria-label="Permalink to &quot;一、客戶集中度變動&quot;">​</a></h3><p>Top 1 甲公司貢獻從 NT$90.57 億（54.67%）降至 NT$51.39 億（25.15%），但同期總營收從 NT$165.66 億增至 NT$204.28 億（+23.3%）。公司並非流失大客戶，而是不流失甲公司的同時成功開拓第二曲線。2025 年乙公司（NT$31.48 億，15.41%）是三年來首次出現第二家逾 10% 客戶。但年報依 IFRS 8 僅揭露逾 10% 客戶，前十大累計佔比不明。</p><h3 id="二、掉單壓力測試" tabindex="-1">二、掉單壓力測試 <a class="header-anchor" href="#二、掉單壓力測試" aria-label="Permalink to &quot;二、掉單壓力測試&quot;">​</a></h3><p>假設甲公司全額歸零：營收損失 NT$51.39 億，對應營業毛利損失約 NT$7.19 億（假設毛利率同平均 14%）。剩餘營收 NT$152.89 億，若營業費用維持 NT$15.04 億，營業利益從 NT$14.10 億降至約 NT$6.91 億（-51.0%），營益率從 6.9% 降至 4.5%。公司仍可維持獲利，證明了分散化的存活緩衝。若回到 2023 年 54.67% 水準，掉單將直接導致營虧。</p><h3 id="三、供應鏈韌性" tabindex="-1">三、供應鏈韌性 <a class="header-anchor" href="#三、供應鏈韌性" aria-label="Permalink to &quot;三、供應鏈韌性&quot;">​</a></h3><p>韓系原廠（三星、SK海力士）佔比約 70%，美光約 20%，南亞科約 10%。十銓本質上仰賴原廠配額——一旦三星/SK 優先供貨 HBM 給 CSP 客戶，中小模組廠將受擠壓。子公司 TEAM DATASOLUTION USA INC. 內部採購 NT$31.55 億（佔總採購 9.62%），DATACELL 約 NT$18.09 億（8.53%），但為集團內部交易，非外部供應商資訊揭露。</p><h3 id="四、區域集中風險" tabindex="-1">四、區域集中風險 <a class="header-anchor" href="#四、區域集中風險" aria-label="Permalink to &quot;四、區域集中風險&quot;">​</a></h3><p>2025 年美洲區營收佔比 69.5%（2024 年 71.9%），亞洲（不含台灣）僅 15.6%。甲公司與乙公司大概率為美洲客戶，地緣關稅與匯率波動將直接衝擊七成營收。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>十銓在 2023→2025 年完成了教科書級的客戶分散：Top 1 從 54.67% 砍至 25.15%，新增第二家逾 10% 客戶，毛利率從 8% 升至 14%，EPS 從 NT$3.38 跳至 NT$13.06。甲公司連續三年居第一大客戶，累計貢獻 NT$229.64 億營收，屬長期 Tier 1 標籤客戶。十銓證明了自己能同時維繫大客戶並拓展新業務。掉單壓力測試顯示極端情境下仍可維持正營益率（4.5%）。但十四銓本質上仍是記憶體通路加值商，利潤空間被上游原廠與下游大客戶雙向擠壓。</p><h3 id="🏳-華爾街空頭視角" tabindex="-1">🏳 華爾街空頭視角 <a class="header-anchor" href="#🏳-華爾街空頭視角" aria-label="Permalink to &quot;🏳 華爾街空頭視角&quot;">​</a></h3><ul><li><p><strong>看空論點一：供應鏈集中度將在超額週期中反噬利潤。</strong> 2025-2026 年三星/SK/美光將逾 60% DRAM 產能轉向 HBM，模組廠標準品配額被擠壓。十銓 70% 韓系佔比，議價空間極小。原廠漲價或縮額將迫十銓以更高成本出貨給大客戶，毛利率遭急遽壓縮。2025 年的漲價順風是賣方市場紅利，一旦轉向供不應求，中游通路商利潤最快被擠乾。</p></li><li><p><strong>看空論點二：甲公司的「代採購」模式暗示去中間化風險。</strong> 年報明載十銓提供代採購服務（代客戶向廠商採買原料），暗示甲公司可能將十銓視為供應鏈工具，而非不可替代夥伴。若甲公司評估直接向原廠下單效益更高，或引入第二家模組廠競價，十銓將面臨去中間化。甲公司絕對金額 NT$51.39 億仍佔近四分之一，換約動盪足以顯著衝擊季度獲利。</p></li></ul><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>2023 年度合併財報</strong>：P.62 - 重要客戶資訊：甲公司佔營收 54.67%（NT$9,057,305K）；P.13 - 營收 NT$16,566,276K，毛利率 8%，營業費用 NT$988,061K，營業利益 NT$308,964K</li><li><strong>2024 年度合併財報</strong>：P.63 - 重要客戶資訊：甲公司佔營收 43.97%（NT$8,767,208K）；P.13 - 營收 NT$19,938,459K，毛利率 11%，營業費用 NT$1,688,565K，營業利益 NT$537,489K</li><li><strong>2025 年度合併財報</strong>：P.63 - 重要客戶資訊：甲公司佔營收 25.15%（NT$5,138,650K），乙公司佔營收 15.41%（NT$3,148,056K）；P.13 - 營收 NT$20,428,449K，毛利率 14%，營業費用 NT$1,504,391K，營業利益 NT$1,410,027K；P.32 - 代採購交易說明</li><li><strong>外部供應鏈資訊</strong>：十銓官網供應商管理頁面 + 媒體法說報導（韓系原廠~70%、美系~20%、台系~10%）</li><li><strong>年報限制</strong>：依 IFRS 8 僅揭露逾 10% 之大客戶，前十大完整名單與佔比無法取得；外部供應商名稱與佔比於財報中未強制揭露</li></ul>',25)])])}const p=a(e,[["render",n]]);export{_ as __pageData,p as default};
